const Units={RADIANS:"radians",DEGREES:"degrees",FEET:"ft",METERS:"m",PIXELS:"pixels",TILE_PIXELS:"tile-pixels",USFEET:"us-ft"},unitByCode={9001:Units.METERS,9002:Units.FEET,9003:Units.USFEET,9101:Units.RADIANS,9102:Units.DEGREES};function fromCode(E){return unitByCode[E]}const METERS_PER_UNIT={};METERS_PER_UNIT[Units.RADIANS]=6370997/(2*Math.PI),METERS_PER_UNIT[Units.DEGREES]=2*Math.PI*6370997/360,METERS_PER_UNIT[Units.FEET]=.3048,METERS_PER_UNIT[Units.METERS]=1,METERS_PER_UNIT[Units.USFEET]=1200/3937;export default Units;export{fromCode,METERS_PER_UNIT};